import type { TransformedToken } from 'style-dictionary';

import { FILE_HEADER } from '../constants.js';
import { type Formatter, type Mode } from '../types.js';
import { getTokenName, getTokenValue, sortByName, splitModes } from './utils.js';

const getTokenLine = (token: TransformedToken, mode: Mode) => {
  return `  --${getTokenName(token, mode)}: ${getTokenValue(token)};`;
};

export const formatCss: Formatter = ({ dictionary, options }): string => {
  const { light, dark } = splitModes(dictionary.allTokens, ['light', 'dark']);

  const lightLines = sortByName(light ?? [], 'light').map((token) => {
    return getTokenLine(token, 'light');
  });

  const darkLines = sortByName(dark ?? [], 'dark').map((token) => {
    return getTokenLine(token, 'dark');
  });

  const finalLines = [
    FILE_HEADER,
    ':root,',
    ':root .light,',
    ':root.light {',
    ...lightLines,
    '}',
    '',
    ':root .dark,',
    ':root.dark {',
    ...darkLines,
    '}',
    '',
  ];
  return finalLines.join('\n');
};
